MERGE INTO CONSULTAS FIN USING (SELECT '000767BoletinDiarioInicialyFinal' INFORME ,TO_CLOB(q'[SELECT 
  COMPROBANTE_CNT.COMPANIA,
  COMPROBANTE_CNT.FECHA,
  TIPO_COMPROBANTE.CLASE_CONTABLE,
  MIN(COMPROBANTE_CNT.NUMERO) MINIMO,
  COMPROBANTE_CNT.TIPO,
  TIPO_COMPROBANTE.NOMBRE,
  MAX(COMPROBANTE_CNT.NUMERO) MAXIMO
FROM COMPROBANTE_CNT 
  LEFT JOIN TIPO_COMPROBANTE 
     ON COMPROBANTE_CNT.COMPANIA = TIPO_COMPROBANTE.COMPANIA
    AND COMPROBANTE_CNT.TIPO = TIPO_COMPROBANTE.CODIGO
WHERE COMPROBANTE_CNT.COMPANIA=s$compania$s
  AND TIPO_COMPROBANTE.CLASE_CONTABLE IN ('S','B','I','E','G','D','A','J','L')
  AND TO_CHAR(COMPROBANTE_CNT.FECHA,'DD/MM/YYYY') = 's$fecha$s'
GROUP BY COMPROBANTE_CNT.COMPANIA, COMPROBANTE_CNT.FECHA, TIPO_COMPROBANTE.CLASE_CONTABLE, COMPROBANTE_CNT.TIPO, TIPO_COMPROBANTE.NOMBRE]') CONSULTA, 1 APLICACION ,TO_CLOB(q'[]') CONSULTA_OPCIONAL, NULL CREATED_BY, NULL MODIFIED_BY  FROM DUAL ) INI ON (INI.INFORME = FIN.INFORME )  WHEN MATCHED THEN  UPDATE SET FIN.CONSULTA =  INI.CONSULTA, FIN.APLICACION =  INI.APLICACION, FIN.CONSULTA_OPCIONAL =  INI.CONSULTA_OPCIONAL, FIN.MODIFIED_BY = INI.MODIFIED_BY, FIN.DATE_MODIFIED = SYSDATE  WHEN NOT MATCHED THEN  INSERT (INFORME,CONSULTA, APLICACION,CONSULTA_OPCIONAL,CREATED_BY,DATE_CREATED)  VALUES (INI.INFORME,INI.CONSULTA, INI.APLICACION,INI.CONSULTA_OPCIONAL,INI.CREATED_BY,SYSDATE);

MERGE INTO CONSULTAS_SUB FIN USING (SELECT '000764LisBoletinDiarioTesoreriaCOS' INFORME_PADRE, '000767BoletinDiarioInicialyFinal' INFORME_HIJO, 'PR_STRSQL_SECUNDARIO40' PARAMETRO ,NULL CREATED_BY, NULL MODIFIED_BY  FROM DUAL ) INI ON (FIN.INFORME_PADRE = INI.INFORME_PADRE AND INI.INFORME_HIJO = FIN.INFORME_HIJO)  WHEN MATCHED THEN  UPDATE SET FIN.PARAMETRO = INI.PARAMETRO , FIN.MODIFIED_BY = INI.MODIFIED_BY, FIN.DATE_MODIFIED = SYSDATE  WHEN NOT MATCHED THEN  INSERT (INFORME_PADRE,INFORME_HIJO, PARAMETRO,CREATED_BY,DATE_CREATED)  VALUES (INI.INFORME_PADRE,INI.INFORME_HIJO, INI.PARAMETRO,INI.CREATED_BY,SYSDATE);
MERGE INTO CONSULTAS_SUB FIN USING (SELECT '002437LisBoletinDiarioTesoreriaCOR' INFORME_PADRE, '000767BoletinDiarioInicialyFinal' INFORME_HIJO, 'PR_STRSQL_SECUNDARIO40' PARAMETRO ,NULL CREATED_BY, NULL MODIFIED_BY  FROM DUAL ) INI ON (FIN.INFORME_PADRE = INI.INFORME_PADRE AND INI.INFORME_HIJO = FIN.INFORME_HIJO)  WHEN MATCHED THEN  UPDATE SET FIN.PARAMETRO = INI.PARAMETRO , FIN.MODIFIED_BY = INI.MODIFIED_BY, FIN.DATE_MODIFIED = SYSDATE  WHEN NOT MATCHED THEN  INSERT (INFORME_PADRE,INFORME_HIJO, PARAMETRO,CREATED_BY,DATE_CREATED)  VALUES (INI.INFORME_PADRE,INI.INFORME_HIJO, INI.PARAMETRO,INI.CREATED_BY,SYSDATE);